import "../styles/Services.css";

export default function Services() {
  const services = [
    { name: "Web Design & Development", logo: "https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.0.0-beta3/svgs/solid/laptop-code.svg" },
    { name: "Mobile App Development", logo: "https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.0.0-beta3/svgs/solid/mobile-alt.svg" },
    { name: "Brand Identity & Logo Design", logo: "https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.0.0-beta3/svgs/solid/palette.svg" },
    { name: "UI/UX Prototyping", logo: "https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.0.0-beta3/svgs/solid/keyboard.svg" },
    { name: "Digital Marketing", logo: "https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.0.0-beta3/svgs/solid/megaphone.svg" },
    { name: "SEO Optimization", logo: "https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.0.0-beta3/svgs/solid/search-dollar.svg" },
    { name: "E-Commerce Solutions", logo: "https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.0.0-beta3/svgs/solid/shopping-cart.svg" },
    { name: "Social Media Strategy", logo: "https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.0.0-beta3/svgs/solid/comments.svg" },
    { name: "Cloud Integration", logo: "https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.0.0-beta3/svgs/solid/cloud-upload-alt.svg" },
    { name: "Consulting & Strategy", logo: "https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.0.0-beta3/svgs/solid/briefcase.svg" },
  ];

  return (
    <section className="services-section">
      <h3 className="section-title">Our Services</h3>
      <ul className="services-list">
        {services.map((service, index) => (
          <li key={index} className="service-item">
            <img src={service.logo} alt={service.name} className="service-logo" />
            <span>{service.name}</span>
          </li>
        ))}
      </ul>
    </section>
  );
}
